change.add:
/**
 * Get the ID of the most recent execution matching filters
 */
export async function getLatestExecutionId(
  organizationId: number,
  branch?: string,
  suite?: string
): Promise<number | null> {
  const sql = getSql()

  const conditions = [`organization_id = ${organizationId}`]
  if (branch) conditions.push(`branch = '${branch}'`)
  if (suite) conditions.push(`suite = '${suite}'`)

  const whereClause = conditions.join(" AND ")

  const result = await sql`
    SELECT id FROM test_executions
    WHERE ${sql.unsafe(whereClause)}
      AND completed_at IS NOT NULL
    ORDER BY started_at DESC
    LIMIT 1
  `

  return result[0]?.id ?? null
}

